"layout\">default</ac:adf-attribute>\n    </ac:adf-node>\n  </ac:adf-fallback>\n<ac:plain-text-body><![CDATA[\n100PRINT\\PRINT\"READY\"\\\"PRINT\n110 INPUT $A\\IF A=253 THEN 300\\INPUT $B\\IF B=253 THEN 300\n120LETK=10*A+B\n130IFK<>2313THEN140\\PRINT\"N  NO FILE YOU BOOB\"\\GOTO100\n140IFK<>2143THEN150\\PRINT\"TALOG  TRY MONTGOMERY WARD'S\"\\GOTO100\n150IFK<>2241THEN160\\PRINT\"STNH  I DON'T FEEL LIKE IT\"\\GOTO100\n160IFK<>2257THEN170\\PRINT\"W YES I'M QUITE NEW\"\\GOTO100\n170IFK<>2274THEN190\\PRINT\"D I'M NOT THAT OLD, BUT I'M OLD ENOUGH!!!\"\n180GOTO100\n190IFK<>2297THEN210\\PRINT\"NAME  WHY? I LIKE MY NAME\"\\GOTO100\n200IFK<>207THEN210\\PRINT\"NAME  WHY? I LIKE MY NAME\"\\GOTO100\n210IFK<>2157THEN220\\PRINT\"BUG  GET A CAN OF RAID\"\\GOTO100\n220IFK<>2322THEN230\\PRINT\"OP THE FUN IS JUST STARTING\"\\GOTO100\n230IFK<>2303THEN240\\PRINT\"VE I DON'T LIKE BANKS\"\\GOTO100\n240IFK<>2336THEN250\\PRINT\"SAVE O.K., THE WHOLE DEC TAPE\"\\CHAIN \"ZOOP  \"\n250IFK<>2305THEN260\\PRINT\"RATCH  GOT AN ITCH?\"\\GOTO100\n260IFK<>2166THEN270\\PRINT\"IT  THIS IS NO NEWSPAPER\"\\GOTO100\n270 INPUT $C\\IF C=253 THEN 300\n280IFC<>141THEN270\n290PRINT\\PRINT\"WHAT???\"\\GOTO100\n300 PRINT \" WIPED OUT COMPLETELY!!!\"\n310 CHAIN \"DEMON \"\n320END\n]]></ac:plain-text-body>\n</ac:adf-extension>\n";
export const BASIC_FIRST_GAME_PAGE_STORAGE_XML = "<h1>101 BASIC Computer Games - First Entry</h1>\n\n<p>This stub page is generated from the <code>101-BASIC-Computer-Games-v.1.0.2</code> directory. Each section is a BASIC macro body ready to prepare and run in the Confluence runner.</p>\n\n<ac:structured-macro ac:name=\"toc\" />\n\n<h2>1CHECK</h2>\n<ac:adf-extension>\n  <ac:adf-node type=\"extension\">\n    <ac:adf-attribute key=\"extension-key\">56be77c8-a94a-4580-a686-76856c812c75/65a2485d-b216-421d-a172-a6abefca842e/static/basic-m6502-macro</ac:adf-attribute>\n    <ac:adf-attribute key=\"extension-type\">com.atlassian.ecosystem</ac:adf-attribute>\n    <ac:adf-attribute key=\"parameters\">\n      <ac:adf-parameter key=\"local-id\">ed02c326-0f64-4019-a61a-7c1e2314f891</ac:adf-parameter>\n      <ac:adf-parameter key=\"extension-id\">ari:cloud:ecosystem::extension/56be77c8-a94a-4580-a686-76856c812c75/65a2485d-b216-421d-a172-a6abefca842e/static/basic-m6502-macro</ac:adf-parameter>\n      <ac:adf-parameter key=\"extension-title\">Microsoft 6502 BASIC (Development)</ac:adf-parameter>\n      <ac:adf-parameter key=\"layout\">extension</ac:adf-parameter>\n      <ac:adf-parameter key=\"forge-environment\">DEVELOPMENT</ac:adf-parameter>\n      <ac:adf-parameter key=\"embedded-macro-context\">\n        <ac:adf-parameter key=\"extension-data\">\n          <ac:adf-parameter key=\"type\">macro</ac:adf-parameter>\n        </ac:adf-parameter>\n      </ac:adf-parameter>\n    </ac:adf-attribute>\n    <ac:adf-attribute key=\"text\">1CHECK</ac:adf-attribute>\n    <ac:adf-attribute key=\"layout\">default</ac:adf-attribute>\n  </ac:adf-node>\n  <ac:adf-fallback>\n    <ac:adf-node type=\"extension\">\n      <ac:adf-attribute key=\"extension-key\">56be77c8-a94a-4580-a686-76856c812c75/65a2485d-b216-421d-a172-a6abefca842e/static/basic-m6502-macro</ac:adf-attribute>\n      <ac:adf-attribute key=\"extension-type\">com.atlassian.ecosystem</ac:adf-attribute>\n      <ac:adf-attribute key=\"parameters\">\n        <ac:adf-parameter key=\"local-id\">f76bfbac-8941-46bb-8199-e2e6001b7c4d</ac:adf-parameter>\n        <ac:adf-parameter key=\"extension-id\">ari:cloud:ecosystem::extension/56be77c8-a94a-4580-a686-76856c812c75/65a2485d-b216-421d-a172-a6abefca842e/static/basic-m6502-macro</ac:adf-parameter>\n        <ac:adf-parameter key=\"extension-title\">Microsoft 6502 BASIC (Development)</ac:adf-parameter>\n        <ac:adf-parameter key=\"layout\">extension</ac:adf-parameter>\n        <ac:adf-parameter key=\"forge-environment\">DEVELOPMENT</ac:adf-parameter>\n      </ac:adf-attribute>\n      <ac:adf-attribute key=\"text\">1CHECK</ac:adf-attribute>\n      <ac:adf-attribute key=\"layout\">default</ac:adf-attribute>\n    </ac:adf-node>\n  </ac:adf-fallback>\n<ac:plain-text-body><![CDATA[\n5 PRINT\n10 PRINT \"SOLITAIRE CHECKER PUZZLE BY DAVID AHL\"\n15 PRINT\n20 PRINT \"48 CHECKERS ARE PLACED ON THE 2 OUTSIDE SPACES OF A\"\n25 PRINT \"STANDARD 64-SQUARE CHECKERBOARD.  THE OBJECT IS TO\"\n30 PRINT \"REMOVE AS MANY CHECKERS AS POSSIBLE BY DIAGONAL JUMPS\"\n35 PRINT \"(AS IN STANDARD CHECKERS).  USE THE NUMBERED BOARD TO\"\n40 PRINT \"INDICATE THE SQUARE YOU WISH TO JUMP FROM AND TO.  ON\"\n45 PRINT \"THE BOARD PRINTED OUT ON EACH TURN '1' INDICATES A\"\n50 PRINT \"CHECKER AND '0' AN EMPTY SQUARE.  WHEN YOU HAVE NO\"\n55 PRINT \"POSSIBLE JUMPS REMAINING, INPUT A '0' IN RESPONSE TO\"\n60 PRINT \"QUESTION 'JUMP FROM ?'\"\n62 PRINT\n65 PRINT \"HERE IS THE NUMERICAL BOARD:\"\n66 PRINT\n68 DIM A(64)\n70 FOR J=1 TO 57 STEP 8\n72 B$=\"## ##  ##  ##  ##  ##  ##  ##\"\n74 PRINT USING B$;J,J+1,J+2,J+3,J+4,J+5,J+6,J+7\n76 NEXT J\n77 PRINT\n78 PRINT \"AND HERE IS THE OPENING POSITION OF THE CHECKERS:\"\n79 PRINT\n80 FOR J=1 TO 64\n82 A(J)=1\n84 NEXT J\n86 FOR J=19 TO 43 STEP 8\n88 FOR I=J TO J+3\n90 A(I)=0\n92 NEXT I\n94 NEXT J\n96 M=0\n98 GOTO 340\n100 INPUT \"JUMP FROM\";F\n105 IF F=0 THEN 500\n110 INPUT \"TO\";T\n112 PRINT\n118 REM *** CHECK LEGALITY OF MOVE\n120 F1=INT((F-1)/8)\n130 F2=F-8*F1\n140 T1=INT((T-1)/8)\n150 T2=T-8*T1\n160 IF F1>7 THEN 230\n170 IF T1>7 THEN 230\n180 IF F2>8 THEN 230\n190 IF T2>8 THEN 230\n200 IF ABS(F1-T1)<>2 THEN 230\n210 IF ABS(F2-T2)<>2 THEN 230\n212 IF A((T+F)/2)=0 THEN 230\n215 IF A(F)=0 THEN 230\n220 IF A(T)=1 THEN 230\n225 GOTO 250\n230 PRINT \"ILLEGAL MOVE.  TRY AGAIN...\"\n240 GOTO 100\n245 REM *** UPDATE BOARD\n250 A(T)=1\n260 A(F)=0\n270 A((T+F)/2)=0\n290 M=M+1\n310 REM *** PRINT BOARD\n340 FOR J=1 TO 57 STEP 8\n350 FOR I=J TO J+7\n360 PRINT A(I);\n370 NEXT I\n380 PRINT\n390 NEXT J\n400 PRINT\n410 GOTO 100\n490 REM *** END GAME SUMMARY\n500 S=0\n510 FOR I=1 TO 64\n520 S=S+A(I)\n530 NEXT I\n535 PRINT\n540 PRINT \"YOU MADE\"M\"JUMPS AND HAD\"S\"PIECES\"\n550 PRINT \"REMAINING ON THE BOARD.\"\n560 PRINT\n562 INPUT \"TRY AGAIN\";A$\n570 IF A$=\"YES\" THEN 70\n575 IF A$=\"NO\" THEN 600\n580 PRINT \"PLEASE ANSWER 'YES' OR 'NO'.\"\n590 GOTO 562\n600 PRINT\n610 PRINT \"O.K.  HOPE YOU HAD FUN!\"\n999 END\n]]></ac:plain-text-body>\n</ac:adf-extension>\n";
